mapper.select:
SELECT id, user_id, nickname, avatar, phone, email, gender, age, region, create_time, update_time, bio
FROM user_profile
WHERE user_id = #{userId}

mapper.update:
UPDATE user_profile
nickname = #{dto.nickname}, avatar = #{dto.avatar}, phone = #{dto.phone}, email = #{dto.email}, gender = #{dto.gender}, age = #{dto.age}, region = #{dto.region}, bio = #{dto.bio}, update_time = NOW()
WHERE user_id = #{userId}
